// Academia Matupá - Processamento de Mensagens WhatsApp
// Número de teste: +5566999301589

const body = $input.all()[0].json.body;
const webhookBody = body || $input.all()[0].json;

// Extrair dados da mensagem
const entry = webhookBody.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const messages = value?.messages?.[0];
const contacts = value?.contacts?.[0];

// Dados da mensagem
const from = messages?.from;
const messageText = messages?.text?.body || '';
const messageType = messages?.type;
const messageId = messages?.id;
const timestamp = messages?.timestamp;

// Dados do contato
const contactName = contacts?.profile?.name || 'Cliente';
const phoneNumberId = value?.metadata?.phone_number_id;

// Log detalhado
console.log('='.repeat(50));
console.log('📱 ACADEMIA MATUPÁ - MENSAGEM RECEBIDA');
console.log('='.repeat(50));
console.log('👤 De:', from);
console.log('📝 Nome:', contactName);
console.log('💬 Mensagem:', messageText);
console.log('📱 Tipo:', messageType);
console.log('🆔 ID:', messageId);
console.log('⏰ Timestamp:', new Date(timestamp * 1000).toLocaleString('pt-BR'));
console.log('📞 Phone ID:', phoneNumberId);
console.log('='.repeat(50));

// Verificar se é mensagem de texto
if (messageType === 'text' && messageText) {
  const texto = messageText.toLowerCase().trim();
  let resposta = '';
  let categoria = 'geral';

  // Análise da mensagem e geração de resposta
  if (texto.includes('teste') || texto.includes('test')) {
    categoria = 'teste';
    resposta = `✅ *TESTE REALIZADO COM SUCESSO!*

🏋️ Academia Matupá - Sistema Online!
📱 Bot funcionando perfeitamente!
⏰ ${new Date().toLocaleString('pt-BR')}
👤 Olá ${contactName}!

Digite *menu* para ver todas as opções! 💪`;

  } else if (texto.includes('menu') || texto.includes('opções') || texto.includes('opcoes')) {
    categoria = 'menu';
    resposta = `📋 *MENU ACADEMIA MATUPÁ*

🧪 *teste* → Testar sistema
ℹ️ *info* → Informações completas
💰 *precos* → Planos e valores
📍 *endereco* → Nossa localização
🕐 *horarios* → Funcionamento
💪 *modalidades* → Atividades
📝 *matricula* → Quero me matricular
📞 *contato* → Falar com consultor
🛑 *parar* → Parar mensagens

💬 Digite qualquer opção acima!`;

  } else if (texto.includes('info') || texto.includes('informação') || texto.includes('informacao')) {
    categoria = 'informacoes';
    resposta = `🏋️ *ACADEMIA MATUPÁ*

📍 *Local:* Matupá - MT
👥 *Membros ativos:* 457
📈 *Taxa de retenção:* 96%
⭐ *Avaliação:* 4.9/5.0

💪 *Diferenciais:*
• Equipamentos de última geração
• Profissionais qualificados
• Ambiente climatizado
• Estacionamento gratuito
• Aulas em grupo inclusas

🎁 *PROMOÇÃO ESPECIAL:*
• 1ª semana GRÁTIS
• Avaliação física gratuita
• Plano alimentar incluso

📱 Interessado? Digite *matricula*`;

  } else if (texto.includes('preço') || texto.includes('preco') || texto.includes('valor') || texto.includes('plano') || texto.includes('precos')) {
    categoria = 'precos';
    resposta = `💰 *PLANOS ACADEMIA MATUPÁ*

🥉 *PLANO BÁSICO - R$ 89,90/mês*
• Musculação completa
• 1 modalidade à escolha
• Horário livre

🥈 *PLANO PREMIUM - R$ 129,90/mês*
• Tudo do Básico +
• Todas as modalidades
• Acompanhamento nutricional
• App exclusivo

🥇 *PLANO VIP - R$ 179,90/mês*
• Tudo do Premium +
• Personal trainer 2x/semana
• Avaliações mensais
• Prioridade nas aulas

💎 *PLANO FAMÍLIA - R$ 299,90/mês*
• Até 4 pessoas
• Todos os benefícios VIP
• Desconto em produtos

📱 Para fechar hoje: *matricula*`;

  } else if (texto.includes('matricula') || texto.includes('matrícula') || texto.includes('sim') || texto.includes('interessado') || texto.includes('quero')) {
    categoria = 'matricula';
    resposta = `🎉 *ÓTIMO ${contactName.toUpperCase()}! VAMOS COMEÇAR!*

📝 *Para sua matrícula precisamos:*
• RG e CPF
• Comprovante de endereço
• Atestado médico (ou fazemos aqui)

🎁 *OFERTA ESPECIAL HOJE:*
• Taxa de matrícula GRÁTIS (R$ 50,00)
• 1ª semana experimental
• Avaliação física completa
• Kit welcome (squeeze + toalha)

📞 *Próximo passo:*
Nossa consultora vai te chamar para:
• Agendar sua visita
• Conhecer a academia
• Fazer sua avaliação
• Finalizar matrícula

⏰ Qual o melhor horário para te ligar?
• Manhã (8h-12h)
• Tarde (14h-18h)
• Noite (18h-20h)

Digite o período preferido! 📱`;

  } else if (texto.includes('parar') || texto.includes('stop') || texto.includes('sair')) {
    categoria = 'parar';
    resposta = `👋 *MENSAGENS PAUSADAS*

Obrigado pelo interesse na Academia Matupá, ${contactName}! 🏋️

📱 Para reativar, envie qualquer mensagem
💪 Estaremos sempre aqui quando precisar!

*Que tal dar uma chance para sua saúde?*
A primeira semana é GRÁTIS! 🎁`;

  } else {
    categoria = 'boas-vindas';
    resposta = `👋 *Olá ${contactName}! Bem-vindo à Academia Matupá!* 🏋️

💪 Somos a academia mais completa de Matupá!
📈 457 membros satisfeitos e você pode ser o próximo!

📋 *Digite uma das opções:*
• *menu* → Ver todas as opções
• *info* → Conhecer a academia
• *precos* → Ver planos
• *matricula* → Quero me matricular

🎁 *OFERTA ESPECIAL:*
1ª semana GRÁTIS + avaliação!

Como posso ajudar você hoje? 😊`;
  }

  // Retornar dados para envio
  return {
    json: {
      to: from,
      message: resposta,
      phoneNumberId: phoneNumberId,
      categoria: categoria,
      contactName: contactName,
      originalMessage: messageText,
      timestamp: new Date().toISOString(),
      messageId: messageId
    }
  };
}

// Se não for mensagem de texto, pular
return {
  json: {
    skip: true,
    reason: `Tipo de mensagem não suportado: ${messageType}`,
    from: from,
    contactName: contactName
  }
};

// Log da resposta enviada - Academia Matupá
const input = $input.all()[0].json;

console.log('='.repeat(50));
console.log('✅ RESPOSTA ENVIADA - ACADEMIA MATUPÁ');
console.log('='.repeat(50));
console.log('👤 Para:', input.contactName);
console.log('📱 Número:', input.to);
console.log('📝 Categoria:', input.categoria);
console.log('💬 Mensagem original:', input.originalMessage);
console.log('📤 Resposta enviada:', input.message.substring(0, 100) + '...');
console.log('⏰ Timestamp:', input.timestamp);
console.log('🆔 Message ID:', input.messageId);
console.log('='.repeat(50));

// Estatísticas simples
const stats = {
  timestamp: input.timestamp,
  categoria: input.categoria,
  contactName: input.contactName,
  phoneNumber: input.to,
  messageLength: input.message.length,
  originalMessage: input.originalMessage
};

return {
  json: {
    status: 'success',
    message: 'Resposta enviada com sucesso',
    stats: stats,
    sentTo: input.to,
    contactName: input.contactName,
    categoria: input.categoria,
    timestamp: input.timestamp
  }
};

